1	package com.eaglepoint.storehub.config;
2	
3	import jakarta.servlet.*;
4	import jakarta.servlet.http.*;
5	import lombok.RequiredArgsConstructor;
6	import lombok.extern.slf4j.Slf4j;
7	import org.springframework.jdbc.core.JdbcTemplate;
8	import org.springframework.stereotype.Component;
9	import org.springframework.web.filter.OncePerRequestFilter;
10	
11	import java.io.IOException;
12	import java.security.MessageDigest;
13	import java.util.HexFormat;
14	
15	@Slf4j
16	@Component
17	@RequiredArgsConstructor
18	public class IdempotencyFilter extends OncePerRequestFilter {
19	
20	    private final JdbcTemplate jdbcTemplate;
21	
22	    @Override
23	    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
24	                                    FilterChain filterChain) throws ServletException, IOException {
25	        String idempotencyKey = request.getHeader("X-Idempotency-Key");
26	
27	        if (idempotencyKey == null || idempotencyKey.isBlank()) {
28	            filterChain.doFilter(request, response);
29	            return;
30	        }
31	
32	        // Only apply to mutation methods
33	        String method = request.getMethod();
34	        if ("GET".equals(method) || "HEAD".equals(method) || "OPTIONS".equals(method)) {
35	            filterChain.doFilter(request, response);
36	            return;
37	        }
38	
39	        String keyHash = hashKey(idempotencyKey);
40	
41	        // Check if key already used
42	        Integer existingStatus = jdbcTemplate.query(
43	                "SELECT response_status FROM idempotency_keys WHERE key_hash = ?",
44	                (rs, rowNum) -> rs.getInt("response_status"),
45	                keyHash
46	        ).stream().findFirst().orElse(null);
47	
48	        if (existingStatus != null) {
49	            // Replay: return the same status without re-executing
50	            log.info("Idempotency key replay: key={}, previousStatus={}", keyHash.substring(0, 8), existingStatus);
51	            response.setStatus(existingStatus);
52	            response.setContentType("application/json");
53	            response.getWriter().write("{\"replayed\":true,\"originalStatus\":" + existingStatus + "}");
54	            return;
55	        }
56	
57	        // Execute and record
58	        filterChain.doFilter(request, response);
59	
60	        // Record the response status for future replays
61	        try {
62	            jdbcTemplate.update(
63	                    "INSERT INTO idempotency_keys (key_hash, response_status) VALUES (?, ?) ON CONFLICT DO NOTHING",
64	                    keyHash, response.getStatus());
65	        } catch (Exception e) {
66	            log.warn("Failed to record idempotency key: {}", e.getMessage());
67	        }
68	    }
69	
70	    private String hashKey(String key) {
71	        try {
72	            MessageDigest md = MessageDigest.getInstance("SHA-256");
73	            return HexFormat.of().formatHex(md.digest(key.getBytes()));
74	        } catch (Exception e) {
75	            return key;
76	        }
77	    }
78	}
