1	package com.eaglepoint.storehub.aspect;
2	
3	import com.eaglepoint.storehub.entity.User;
4	import com.eaglepoint.storehub.enums.Role;
5	import com.eaglepoint.storehub.repository.OrganizationRepository;
6	import com.eaglepoint.storehub.repository.UserRepository;
7	import com.eaglepoint.storehub.security.UserPrincipal;
8	import jakarta.servlet.http.HttpServletRequest;
9	import lombok.RequiredArgsConstructor;
10	import org.aspectj.lang.ProceedingJoinPoint;
11	import org.aspectj.lang.annotation.Around;
12	import org.aspectj.lang.annotation.Aspect;
13	import org.springframework.security.core.Authentication;
14	import org.springframework.security.core.context.SecurityContextHolder;
15	import org.springframework.stereotype.Component;
16	import org.springframework.web.context.request.RequestContextHolder;
17	import org.springframework.web.context.request.ServletRequestAttributes;
18	
19	import java.util.List;
20	
21	/**
22	 * Intercepts @DataScope-annotated methods and injects multi-dimensional scope context:
23	 * site IDs, team ID, device hash, and work-order ID.
24	 */
25	@Aspect
26	@Component
27	@RequiredArgsConstructor
28	public class DataScopeAspect {
29	
30	    private final OrganizationRepository organizationRepository;
31	    private final UserRepository userRepository;
32	
33	    @Around("@annotation(com.eaglepoint.storehub.annotation.DataScope)")
34	    public Object applyDataScope(ProceedingJoinPoint joinPoint) throws Throwable {
35	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
36	        if (auth != null && auth.getPrincipal() instanceof UserPrincipal principal) {
37	            Role role = Role.valueOf(principal.getRole());
38	
39	            // Site scope
40	            List<Long> visibleSiteIds;
41	            if (role == Role.ENTERPRISE_ADMIN) {
42	                visibleSiteIds = null;
43	            } else if (role == Role.SITE_MANAGER || role == Role.TEAM_LEAD) {
44	                visibleSiteIds = principal.getSiteId() != null
45	                        ? organizationRepository.findAllSiteIdsUnder(principal.getSiteId())
46	                        : List.of();
47	            } else {
48	                visibleSiteIds = principal.getSiteId() != null
49	                        ? List.of(principal.getSiteId())
50	                        : List.of();
51	            }
52	            DataScopeContext.set(visibleSiteIds);
53	
54	            // Team scope
55	            User user = userRepository.findById(principal.getId()).orElse(null);
56	            if (user != null && user.getTeam() != null) {
57	                DataScopeContext.setTeamId(user.getTeam().getId());
58	            }
59	
60	            // Device scope — derive from current request
61	            ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
62	            if (attrs != null) {
63	                HttpServletRequest req = attrs.getRequest();
64	                String deviceHeader = req.getHeader("X-Device-Fingerprint");
65	                if (deviceHeader != null && !deviceHeader.isBlank()) {
66	                    DataScopeContext.setDeviceHash(deviceHeader);
67	                }
68	            }
69	        }
70	
71	        try {
72	            return joinPoint.proceed();
73	        } finally {
74	            DataScopeContext.clear();
75	        }
76	    }
77	}
