1	package com.eaglepoint.storehub.aspect;
2	
3	import java.util.List;
4	
5	/**
6	 * Thread-local scope context for multi-dimensional data isolation.
7	 * Supports: site scope, team scope, device scope, and work-order scope.
8	 */
9	public final class DataScopeContext {
10	
11	    private static final ThreadLocal<List<Long>> VISIBLE_SITE_IDS = new ThreadLocal<>();
12	    private static final ThreadLocal<Long> TEAM_ID = new ThreadLocal<>();
13	    private static final ThreadLocal<String> DEVICE_HASH = new ThreadLocal<>();
14	    private static final ThreadLocal<Long> WORK_ORDER_ID = new ThreadLocal<>();
15	
16	    private DataScopeContext() {}
17	
18	    // --- Site scope ---
19	    public static void set(List<Long> siteIds) { VISIBLE_SITE_IDS.set(siteIds); }
20	    /** null = unrestricted (admin), empty = no access */
21	    public static List<Long> get() { return VISIBLE_SITE_IDS.get(); }
22	
23	    // --- Team scope ---
24	    public static void setTeamId(Long teamId) { TEAM_ID.set(teamId); }
25	    public static Long getTeamId() { return TEAM_ID.get(); }
26	
27	    // --- Device scope ---
28	    public static void setDeviceHash(String hash) { DEVICE_HASH.set(hash); }
29	    public static String getDeviceHash() { return DEVICE_HASH.get(); }
30	
31	    // --- Work-order scope ---
32	    public static void setWorkOrderId(Long id) { WORK_ORDER_ID.set(id); }
33	    public static Long getWorkOrderId() { return WORK_ORDER_ID.get(); }
34	
35	    public static void clear() {
36	        VISIBLE_SITE_IDS.remove();
37	        TEAM_ID.remove();
38	        DEVICE_HASH.remove();
39	        WORK_ORDER_ID.remove();
40	    }
41	}
