1	package com.eaglepoint.storehub.config;
2	
3	import com.eaglepoint.storehub.security.JwtAuthenticationFilter;
4	import lombok.RequiredArgsConstructor;
5	import org.springframework.beans.factory.annotation.Value;
6	import org.springframework.context.annotation.Bean;
7	import org.springframework.context.annotation.Configuration;
8	import org.springframework.security.authentication.AuthenticationManager;
9	import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
10	import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
11	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
12	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
13	import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
14	import org.springframework.security.config.http.SessionCreationPolicy;
15	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
16	import org.springframework.security.crypto.password.PasswordEncoder;
17	import org.springframework.security.web.SecurityFilterChain;
18	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
19	import org.springframework.web.cors.CorsConfiguration;
20	import org.springframework.web.cors.CorsConfigurationSource;
21	import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
22	
23	import java.util.Arrays;
24	import java.util.List;
25	
26	@Configuration
27	@EnableWebSecurity
28	@EnableMethodSecurity
29	@RequiredArgsConstructor
30	public class SecurityConfig {
31	
32	    private final JwtAuthenticationFilter jwtAuthenticationFilter;
33	    private final RateLimitFilter rateLimitFilter;
34	    private final IdempotencyFilter idempotencyFilter;
35	
36	    @Value("${app.cors.allowed-origins:http://localhost:4200}")
37	    private String allowedOrigins;
38	
39	    @Bean
40	    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
41	        http
42	            .csrf(AbstractHttpConfigurer::disable)
43	            .cors(cors -> cors.configurationSource(corsConfigurationSource()))
44	            .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
45	            // Route-level rules provide defense-in-depth; method-level @PreAuthorize is the
46	            // primary authorization mechanism on individual controller methods.
47	            .authorizeHttpRequests(auth -> auth
48	                .requestMatchers("/api/auth/**").permitAll()
49	                .requestMatchers("/api/admin/**").hasRole("ENTERPRISE_ADMIN")
50	                .requestMatchers("/api/audit/**").hasAnyRole("ENTERPRISE_ADMIN", "SITE_MANAGER")
51	                .requestMatchers("/api/credit-score/{userId}").hasAnyRole("ENTERPRISE_ADMIN", "SITE_MANAGER")
52	                .anyRequest().authenticated()
53	            )
54	            .addFilterBefore(idempotencyFilter, UsernamePasswordAuthenticationFilter.class)
55	            .addFilterBefore(rateLimitFilter, UsernamePasswordAuthenticationFilter.class)
56	            .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class);
57	
58	        return http.build();
59	    }
60	
61	    @Bean
62	    public AuthenticationManager authenticationManager(AuthenticationConfiguration config) throws Exception {
63	        return config.getAuthenticationManager();
64	    }
65	
66	    @Bean
67	    public PasswordEncoder passwordEncoder() {
68	        return new BCryptPasswordEncoder(12);
69	    }
70	
71	    @Bean
72	    public CorsConfigurationSource corsConfigurationSource() {
73	        CorsConfiguration config = new CorsConfiguration();
74	        config.setAllowedOrigins(Arrays.asList(allowedOrigins.split(",")));
75	        config.setAllowedMethods(List.of("GET", "POST", "PUT", "DELETE", "PATCH"));
76	        config.setAllowedHeaders(List.of("*"));
77	        config.setAllowCredentials(true);
78	        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
79	        source.registerCorsConfiguration("/**", config);
80	        return source;
81	    }
82	}
