21	@RestController
22	@RequestMapping("/api/audit")
23	@RequiredArgsConstructor
24	public class AuditController {
25	
26	    private final AuditService auditService;
27	    private final SiteAuthorizationService siteAuth;
28	    private final UserRepository userRepository;
29	    private final OrderRepository orderRepository;
30	    private final SupportTicketRepository ticketRepository;
31	    private final CheckInRepository checkInRepository;
32	
33	    @GetMapping("/entity/{entityType}/{entityId}")
34	    @PreAuthorize("hasAnyRole('ENTERPRISE_ADMIN','SITE_MANAGER')")
35	    @RequiresRecentAuth
36	    public ResponseEntity<List<AuditLogDto>> getAuditTrail(
37	            @PathVariable String entityType,
38	            @PathVariable Long entityId) {
39	        enforceEntityScope(entityType, entityId);
40	        List<AuditLogDto> trail = auditService.getAuditTrail(entityType, entityId).stream()
41	                .map(this::toDto).toList();
42	        return ResponseEntity.ok(trail);
43	    }
44	
45	    @GetMapping("/user/{userId}")
46	    @PreAuthorize("hasAnyRole('ENTERPRISE_ADMIN','SITE_MANAGER')")
47	    @RequiresRecentAuth
48	    public ResponseEntity<List<AuditLogDto>> getAuditTrailByUser(@PathVariable Long userId) {
49	        User user = userRepository.findById(userId)
50	                .orElseThrow(() -> new IllegalArgumentException("User not found"));
51	        siteAuth.requireSiteAccess(user.getSite() != null ? user.getSite().getId() : null);
52	        List<AuditLogDto> trail = auditService.getAuditTrailByUser(userId).stream()
53	                .map(this::toDto).toList();
54	        return ResponseEntity.ok(trail);
55	    }
56	
57	    @GetMapping("/range")
58	    @PreAuthorize("hasRole('ENTERPRISE_ADMIN')")
59	    @RequiresRecentAuth
60	    public ResponseEntity<List<AuditLogDto>> getAuditTrailByDateRange(
61	            @RequestParam Instant start,
62	            @RequestParam Instant end) {
63	        List<AuditLogDto> trail = auditService.getAuditTrailByDateRange(start, end).stream()
64	                .map(this::toDto).toList();
65	        return ResponseEntity.ok(trail);
66	    }
67	
68	    private void enforceEntityScope(String entityType, Long entityId) {
69	        boolean isAdmin = false;
70	        org.springframework.security.core.Authentication auth =
71	                org.springframework.security.core.context.SecurityContextHolder.getContext().getAuthentication();
72	        if (auth != null && auth.getPrincipal() instanceof com.eaglepoint.storehub.security.UserPrincipal p) {
73	            isAdmin = "ENTERPRISE_ADMIN".equals(p.getRole());
74	        }
75	
76	        switch (entityType) {
77	            case "Order" -> {
78	                var order = orderRepository.findById(entityId);
79	                if (order.isPresent()) {
80	                    siteAuth.requireSiteAccess(order.get().getSite().getId());
81	                } else if (!isAdmin) {
82	                    throw new com.eaglepoint.storehub.config.AccessDeniedException(
83	                            "Cannot verify scope for deleted/missing entity");
84	                }
85	            }
86	            case "SupportTicket" -> {
87	                var ticket = ticketRepository.findById(entityId);
88	                if (ticket.isPresent()) {
89	                    siteAuth.requireSiteAccess(ticket.get().getOrder().getSite().getId());
90	                } else if (!isAdmin) {
91	                    throw new com.eaglepoint.storehub.config.AccessDeniedException(
92	                            "Cannot verify scope for deleted/missing entity");
93	                }
94	            }
95	            case "CheckIn" -> {
96	                var checkIn = checkInRepository.findById(entityId);
97	                if (checkIn.isPresent()) {
98	                    siteAuth.requireSiteAccess(checkIn.get().getSite().getId());
99	                } else if (!isAdmin) {
100	                    throw new com.eaglepoint.storehub.config.AccessDeniedException(
101	                            "Cannot verify scope for deleted/missing entity");
102	                }
103	            }
104	            default -> {
105	                if (!isAdmin) {
106	                    throw new com.eaglepoint.storehub.config.AccessDeniedException(
107	                            "Audit lookup for entity type '" + entityType + "' requires enterprise admin access");
108	                }
109	            }
110	        }
111	    }
112	
113	    private AuditLogDto toDto(AuditLog log) {
114	        AuditLogDto dto = new AuditLogDto();
115	        dto.setId(log.getId());
116	        dto.setUserId(log.getUserId());
117	        dto.setUsername(log.getUsername());
118	        dto.setDeviceFingerprint(log.getDeviceFingerprint());
119	        dto.setAction(log.getAction());
120	        dto.setEntityType(log.getEntityType());
121	        dto.setEntityId(log.getEntityId());
122	        dto.setBeforeState(log.getBeforeState());
123	        dto.setAfterState(log.getAfterState());
124	        dto.setIpAddress(log.getIpAddress());
125	        dto.setCreatedAt(log.getCreatedAt());
126	        return dto;
127	    }
128	}
