1	package com.eaglepoint.storehub.service;
2	
3	import com.eaglepoint.storehub.config.AccessDeniedException;
4	import com.eaglepoint.storehub.enums.Role;
5	import com.eaglepoint.storehub.repository.OrganizationRepository;
6	import com.eaglepoint.storehub.security.UserPrincipal;
7	import lombok.RequiredArgsConstructor;
8	import org.springframework.security.core.Authentication;
9	import org.springframework.security.core.context.SecurityContextHolder;
10	import org.springframework.stereotype.Service;
11	
12	import java.util.List;
13	
14	@Service
15	@RequiredArgsConstructor
16	public class SiteAuthorizationService {
17	
18	    private final OrganizationRepository organizationRepository;
19	
20	    /**
21	     * Returns true if the current user can access data for the given site ID.
22	     * ENTERPRISE_ADMIN can access all sites.
23	     * SITE_MANAGER/TEAM_LEAD can access their site and child sites.
24	     * STAFF/CUSTOMER can only access their own site.
25	     */
26	    public boolean canAccessSite(Long siteId) {
27	        UserPrincipal principal = getCurrentPrincipal();
28	        if (principal == null) return false;
29	
30	        Role role = Role.valueOf(principal.getRole());
31	        if (role == Role.ENTERPRISE_ADMIN) return true;
32	
33	        // Null site: deny for non-admins (prevents accidental broad access)
34	        if (siteId == null) return false;
35	
36	        Long userSiteId = principal.getSiteId();
37	        if (userSiteId == null) return false;
38	        if (userSiteId.equals(siteId)) return true;
39	
40	        if (role == Role.SITE_MANAGER || role == Role.TEAM_LEAD) {
41	            List<Long> childSites = organizationRepository.findAllSiteIdsUnder(userSiteId);
42	            return childSites.contains(siteId);
43	        }
44	
45	        return false;
46	    }
47	
48	    /**
49	     * Throws AccessDeniedException if the current user cannot access the given site.
50	     */
51	    public void requireSiteAccess(Long siteId) {
52	        if (!canAccessSite(siteId)) {
53	            throw new AccessDeniedException("Access denied: resource belongs to a different site");
54	        }
55	    }
56	
57	    /**
58	     * Checks if the current user is the given user ID, or has a managerial role for the given site.
59	     */
60	    public void requireOwnerOrSiteAccess(Long resourceOwnerId, Long siteId) {
61	        UserPrincipal principal = getCurrentPrincipal();
62	        if (principal == null) throw new AccessDeniedException("Not authenticated");
63	        if (principal.getId().equals(resourceOwnerId)) return;
64	        requireSiteAccess(siteId);
65	        Role role = Role.valueOf(principal.getRole());
66	        if (role != Role.ENTERPRISE_ADMIN && role != Role.SITE_MANAGER && role != Role.TEAM_LEAD && role != Role.STAFF) {
67	            throw new AccessDeniedException("Access denied");
68	        }
69	    }
70	
71	    /**
72	     * Enforces that a device hash matches the expected binding for the operation.
73	     * Call when a device-scoped action requires the device to be the bound one.
74	     */
75	    public void requireDeviceMatch(String expectedHash, String actualHash) {
76	        if (expectedHash != null && !expectedHash.equals(actualHash)) {
77	            throw new AccessDeniedException("Device scope mismatch");
78	        }
79	    }
80	
81	    /**
82	     * Enforces that a work-order/shift assignment exists and is active.
83	     * The shift assignment acts as the work-order binding for check-in operations.
84	     */
85	    public void requireWorkOrderScope(boolean hasActiveAssignment) {
86	        if (!hasActiveAssignment) {
87	            throw new AccessDeniedException("No active work-order/shift assignment for this operation");
88	        }
89	    }
90	
91	    private UserPrincipal getCurrentPrincipal() {
92	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
93	        if (auth != null && auth.getPrincipal() instanceof UserPrincipal p) return p;
94	        return null;
95	    }
96	}
