195	    @DataScope
196	    @Transactional(readOnly = true)
197	    public List<CheckInResponse> getCheckInsBySite(Long siteId, Instant start, Instant end) {
198	        List<Long> visibleSites = DataScopeContext.get();
199	        if (visibleSites != null && !visibleSites.contains(siteId)) {
200	            throw new IllegalArgumentException("Access denied: site not in your data scope");
201	        }
202	        return checkInRepository.findBySiteAndTimeRange(siteId, start, end).stream()
203	                .map(c -> buildResponse(c.getId(), c.getUser().getId(), c.getSite().getId(),
204	                        c.getTimestamp(), c.getScheduledTime(), c.getStatus(), null))
205	                .toList();
206	    }
