208	    /**
209	     * Augments client-provided fingerprint with server-side data (IP + User-Agent hash)
210	     * to make it harder to forge.
211	     */
212	    private String augmentFingerprint(String clientFingerprint) {
213	        try {
214	            ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
215	            String serverPart = "";
216	            if (attrs != null) {
217	                HttpServletRequest req = attrs.getRequest();
218	                String ip = req.getRemoteAddr();
219	                String ua = req.getHeader("User-Agent");
220	                serverPart = ip + "|" + (ua != null ? ua : "");
221	            }
222	            String combined = (clientFingerprint != null ? clientFingerprint : "") + "|" + serverPart;
223	            MessageDigest md = MessageDigest.getInstance("SHA-256");
224	            byte[] hash = md.digest(combined.getBytes(StandardCharsets.UTF_8));
225	            return HexFormat.of().formatHex(hash);
226	        } catch (Exception e) {
227	            return clientFingerprint;
228	        }
229	    }
