231	    @Transactional(readOnly = true)
232	    public List<FraudAlert> getUnresolvedAlerts() {
233	        List<FraudAlert> allAlerts = fraudAlertRepository.findByResolvedFalseOrderByCreatedAtDesc();
234	        // Enterprise admin sees all; others see only in-scope site alerts
235	        return allAlerts.stream().filter(alert -> {
236	            Long alertSiteId = null;
237	            // Derive site from the user's site assignment
238	            if (alert.getUser() != null && alert.getUser().getSite() != null) {
239	                alertSiteId = alert.getUser().getSite().getId();
240	            }
241	            return siteAuth.canAccessSite(alertSiteId);
242	        }).toList();
243	    }
