245	    @Audited(action = "RESOLVE_FRAUD_ALERT", entityType = "FraudAlert")
246	    @Transactional
247	    public FraudAlert resolveFraudAlert(Long alertId, Long resolverId, String note) {
248	        String trimmedNote = note != null ? note.trim() : "";
249	        if (trimmedNote.length() < 10) {
250	            throw new IllegalArgumentException("Supervisor resolution note must be at least 10 characters");
251	        }
252	
253	        FraudAlert alert = fraudAlertRepository.findById(alertId)
254	                .orElseThrow(() -> new IllegalArgumentException("Fraud alert not found"));
255	
256	        // Enforce site-scope on resolution — manager must have access to the alert's site
257	        Long alertSiteId = (alert.getUser() != null && alert.getUser().getSite() != null)
258	                ? alert.getUser().getSite().getId() : null;
259	        siteAuth.requireSiteAccess(alertSiteId);
260	
261	        User resolver = userRepository.findById(resolverId)
262	                .orElseThrow(() -> new IllegalArgumentException("Resolver not found"));
263	
264	        alert.setResolved(true);
265	        alert.setResolverNote(trimmedNote);
266	        alert.setResolvedBy(resolver);
267	        alert.setResolvedAt(Instant.now());
268	
269	        log.info("Fraud alert resolved: alertId={}, resolverId={}", alertId, resolverId);
270	        return fraudAlertRepository.save(alert);
271	    }
