273	    private CheckInResponse buildResponse(Long id, Long userId, Long siteId,
274	                                           Instant timestamp, Instant scheduled,
275	                                           CheckInStatus status, String message) {
276	        return buildResponse(id, userId, siteId, timestamp, scheduled, status, message, null, null);
277	    }
278	
279	    private CheckInResponse buildResponse(Long id, Long userId, Long siteId,
280	                                           Instant timestamp, Instant scheduled,
281	                                           CheckInStatus status, String message,
282	                                           String locationDescription, String deviceHash) {
283	        // Compute timing classification independently from status
284	        // This ensures FLAGGED check-ins still show correct timing (EARLY/LATE/ON_TIME)
285	        String windowClass;
286	        if (scheduled != null && timestamp != null) {
287	            Instant windowStart = scheduled.minus(EARLY_WINDOW);
288	            Instant windowEnd = scheduled.plus(LATE_WINDOW);
289	            if (timestamp.isBefore(windowStart)) {
290	                windowClass = "EARLY";
291	            } else if (timestamp.isAfter(windowEnd)) {
292	                windowClass = "LATE";
293	            } else {
294	                windowClass = "ON_TIME";
295	            }
296	        } else {
297	            windowClass = "UNKNOWN";
298	        }
299	
300	        String maskedDevice = deviceHash != null && deviceHash.length() > 8
301	                ? deviceHash.substring(0, 8) + "..." : null;
302	
303	        return CheckInResponse.builder()
304	                .id(id).userId(userId).siteId(siteId)
305	                .timestamp(timestamp).scheduledTime(scheduled)
306	                .status(status).message(message)
307	                .locationDescription(locationDescription)
308	                .deviceEvidenceToken(maskedDevice)
309	                .windowClassification(windowClass)
310	                .flaggedForReview(status == CheckInStatus.FLAGGED)
311	                .build();
312	    }
