33	@Slf4j
34	@Service
35	@RequiredArgsConstructor
36	public class OrderService {
37	
38	    private static final BigDecimal SHORT_RANGE_FEE = new BigDecimal("4.99");   // 0-5 miles
39	    private static final BigDecimal LONG_RANGE_FEE = new BigDecimal("7.99");    // 5-10 miles
40	    private static final double MAX_DELIVERY_MILES = 10.0;
41	
42	    private final OrderRepository orderRepository;
43	    private final UserRepository userRepository;
44	    private final OrganizationRepository organizationRepository;
45	    private final DeliveryZoneRepository deliveryZoneRepository;
46	    private final DeliveryZoneGroupRepository deliveryZoneGroupRepository;
47	    private final DeliveryZoneGroupService deliveryZoneGroupService;
48	    private final PickupRedemptionLogRepository redemptionLogRepository;
49	    private final SiteAuthorizationService siteAuth;
50	    private final SecureRandom secureRandom = new SecureRandom();
51	
52	    @Audited(action = "CREATE", entityType = "Order")
53	    @Transactional
54	    public OrderResponse createOrder(Long customerId, OrderRequest request) {
55	        User customer = userRepository.findById(customerId)
56	                .orElseThrow(() -> new IllegalArgumentException("Customer not found"));
57	        Organization site = organizationRepository.findById(request.getSiteId())
58	                .orElseThrow(() -> new IllegalArgumentException("Site not found"));
59	
60	        // Enforce site access — customers can only create orders at accessible sites
61	        siteAuth.requireSiteAccess(request.getSiteId());
62	
63	        BigDecimal deliveryFee = BigDecimal.ZERO;
64	        Double distanceMiles = null;
65	        FulfillmentMode mode = request.getFulfillmentMode();
66	
67	        // Mode-specific validation
68	        if (mode == FulfillmentMode.DELIVERY || mode == FulfillmentMode.COURIER_HANDOFF) {
69	            if (request.getDeliveryZip() == null || request.getDeliveryZip().isBlank()) {
70	                throw new IllegalArgumentException("Delivery ZIP code required for " + mode + " orders");
71	            }
72	
73	            // Authoritative pricing: ZIP group + distance band (distance stored per ZIP)
74	            var feeResult = deliveryZoneGroupService.resolveDeliveryFee(
75	                    request.getSiteId(), request.getDeliveryZip());
76	
77	            if (feeResult != null) {
78	                deliveryFee = feeResult.fee();
79	                distanceMiles = feeResult.distanceMiles();
80	            } else {
81	                // Legacy fallback (deprecated) — single-zone exact ZIP match
82	                DeliveryZone legacyZone = deliveryZoneRepository
83	                        .findBySiteIdAndZipCode(request.getSiteId(), request.getDeliveryZip())
84	                        .orElseThrow(() -> new IllegalArgumentException(
85	                                "Delivery not available to ZIP: " + request.getDeliveryZip() +
86	                                ". Configure a delivery zone group with this ZIP code."));
87	
88	                if (!legacyZone.isActive()) {
89	                    throw new IllegalArgumentException("Delivery zone is currently inactive");
90	                }
91	                double distance = legacyZone.getDistanceMiles();
92	                if (distance > MAX_DELIVERY_MILES) {
93	                    throw new IllegalArgumentException("Delivery distance exceeds maximum range");
94	                }
95	                deliveryFee = legacyZone.getDeliveryFee() != null
96	                        ? legacyZone.getDeliveryFee()
97	                        : calculateDefaultFee(distance);
98	                distanceMiles = distance;
99	                log.warn("Using legacy delivery zone pricing for ZIP {} — migrate to zone groups", request.getDeliveryZip());
100	            }
101	        }
102	
103	        BigDecimal total = request.getSubtotal().add(deliveryFee);
104	        String verificationCode = request.isPickup() ? generateVerificationCode() : null;
105	
106	        Order order = Order.builder()
107	                .customer(customer)
108	                .site(site)
109	                .status(OrderStatus.PENDING)
110	                .subtotal(request.getSubtotal())
111	                .deliveryFee(deliveryFee)
112	                .total(total)
113	                .deliveryZip(request.getDeliveryZip())
114	                .deliveryDistanceMiles(distanceMiles)
115	                .fulfillmentMode(mode)
116	                .pickup(request.isPickup())
117	                .pickupVerificationCode(verificationCode)
118	                .courierNotes(request.getCourierNotes())
119	                .build();
120	
121	        order = orderRepository.save(order);
122	        log.info("Order created: orderId={}, customerId={}, siteId={}, pickup={}, total={}", order.getId(), customerId, request.getSiteId(), request.isPickup(), total);
123	        return toResponse(order);
124	    }
125	
126	    @Audited(action = "STATUS_UPDATE", entityType = "Order")
127	    @Transactional
128	    public OrderResponse updateStatus(Long orderId, OrderStatus newStatus) {
129	        Order order = orderRepository.findById(orderId)
130	                .orElseThrow(() -> new IllegalArgumentException("Order not found"));
131	        siteAuth.requireSiteAccess(order.getSite().getId());
132	
133	        // Work-order scope: if order has assigned staff, only that staff (or managers) can update
134	        if (order.getAssignedStaff() != null) {
135	            org.springframework.security.core.Authentication auth =
136	                    org.springframework.security.core.context.SecurityContextHolder.getContext().getAuthentication();
137	            if (auth != null && auth.getPrincipal() instanceof com.eaglepoint.storehub.security.UserPrincipal p) {
138	                String role = p.getRole();
139	                if (!"ENTERPRISE_ADMIN".equals(role) && !"SITE_MANAGER".equals(role)) {
140	                    // STAFF/TEAM_LEAD must be the assigned staff
141	                    if (!order.getAssignedStaff().getId().equals(p.getId())) {
142	                        throw new com.eaglepoint.storehub.config.AccessDeniedException(
143	                                "Work-order scope: only the assigned staff can update this order");
144	                    }
145	                }
146	            }
147	        }
148	
149	        order.setStatus(newStatus);
150	        log.info("Order status updated: orderId={}, newStatus={}", orderId, newStatus);
151	        return toResponse(orderRepository.save(order));
152	    }
153	
154	    @Audited(action = "VERIFY_PICKUP", entityType = "Order")
155	    @Transactional
156	    public OrderResponse verifyPickup(Long orderId, String code, Long requestingUserId, String requestingRole) {
157	        Order order = orderRepository.findByIdAndPickupVerificationCode(orderId, code)
158	                .orElseThrow(() -> new IllegalArgumentException("Invalid order ID or verification code"));
159	
160	        // Customer cannot self-redeem their own pickup code
161	        if (order.getCustomer().getId().equals(requestingUserId)) {
162	            logRedemptionAttempt(order, requestingUserId, "DENIED_CUSTOMER_SELF", "Customer cannot self-redeem");
163	            throw new com.eaglepoint.storehub.config.AccessDeniedException(
164	                    "Pickup verification must be performed by staff, not the order customer");
165	        }
166	
167	        // Verifier must have site access
168	        siteAuth.requireSiteAccess(order.getSite().getId());
169	
170	        if (order.getFulfillmentMode() != FulfillmentMode.PICKUP && !order.isPickup()) {
171	            logRedemptionAttempt(order, requestingUserId, "DENIED_NOT_PICKUP", "Order is not a pickup order");
172	            throw new IllegalArgumentException("Order is not a pickup order");
173	        }
174	        if (order.isPickupVerified()) {
175	            logRedemptionAttempt(order, requestingUserId, "DENIED_ALREADY_VERIFIED", "Pickup already verified");
176	            throw new IllegalArgumentException("Pickup already verified");
177	        }
178	
179	        order.setPickupVerified(true);
180	        order.setStatus(OrderStatus.PICKED_UP);
181	        logRedemptionAttempt(order, requestingUserId, "SUCCESS", null);
182	
183	        User verifier = userRepository.findById(requestingUserId)
184	                .orElseThrow(() -> new IllegalArgumentException("Verifier not found"));
185	        order.setVerifiedBy(verifier);
186	        order.setVerifiedAt(Instant.now());
187	
188	        log.info("Pickup verified: orderId={}, verifiedBy={}", orderId, requestingUserId);
189	        return toResponse(orderRepository.save(order));
190	    }
