204	    @DataScope
205	    @Transactional(readOnly = true)
206	    public List<OrderResponse> getOrdersBySite(Long siteId) {
207	        List<Long> visibleSites = DataScopeContext.get();
208	        if (visibleSites != null && !visibleSites.contains(siteId)) {
209	            throw new com.eaglepoint.storehub.config.AccessDeniedException("Access denied: site not in your data scope");
210	        }
211	        List<Order> orders = orderRepository.findBySiteIdOrderByCreatedAtDesc(siteId);
212	        // Multi-dimensional scope enforcement
213	        Long teamId = DataScopeContext.getTeamId();
214	        if (teamId != null) {
215	            // Staff with team assignment: see only orders assigned to them or unassigned at their site
216	            org.springframework.security.core.Authentication auth =
217	                    org.springframework.security.core.context.SecurityContextHolder.getContext().getAuthentication();
218	            if (auth != null && auth.getPrincipal() instanceof com.eaglepoint.storehub.security.UserPrincipal p) {
219	                Long staffId = p.getId();
220	                orders = orders.stream().filter(o ->
221	                        o.getAssignedStaff() == null // unassigned orders visible to all site staff
222	                        || o.getAssignedStaff().getId().equals(staffId) // assigned to this staff
223	                        || o.getVerifiedBy() != null && o.getVerifiedBy().getId().equals(staffId) // verified by this staff
224	                ).toList();
225	            }
226	        }
227	        return orders.stream().map(o -> toResponse(o, false)).toList();
228	    }
229	
230	    @DataScope
231	    @Transactional(readOnly = true)
232	    public org.springframework.data.domain.Page<OrderResponse> getOrdersBySite(Long siteId, org.springframework.data.domain.Pageable pageable) {
233	        List<Long> visibleSites = DataScopeContext.get();
234	        if (visibleSites != null && !visibleSites.contains(siteId)) {
235	            throw new com.eaglepoint.storehub.config.AccessDeniedException("Access denied: site not in your data scope");
236	        }
237	        // Multi-dimensional scope: team-scoped staff sees only assigned/unassigned orders
238	        Long teamId = DataScopeContext.getTeamId();
239	        if (teamId != null) {
240	            org.springframework.security.core.Authentication auth =
241	                    org.springframework.security.core.context.SecurityContextHolder.getContext().getAuthentication();
242	            if (auth != null && auth.getPrincipal() instanceof com.eaglepoint.storehub.security.UserPrincipal p) {
243	                return orderRepository.findBySiteIdScopedToStaff(siteId, p.getId(), pageable)
244	                        .map(o -> toResponse(o, false));
245	            }
246	        }
247	        return orderRepository.findBySiteIdOrderByCreatedAtDesc(siteId, pageable)
248	                .map(o -> toResponse(o, false));
249	    }
