251	    @Transactional(readOnly = true)
252	    public OrderResponse getOrder(Long orderId, Long requestingUserId, String requestingRole) {
253	        Order order = orderRepository.findById(orderId)
254	                .orElseThrow(() -> new IllegalArgumentException("Order not found"));
255	        siteAuth.requireOwnerOrSiteAccess(order.getCustomer().getId(), order.getSite().getId());
256	        boolean isOwner = order.getCustomer().getId().equals(requestingUserId);
257	        return toResponse(order, isOwner);
258	    }
259	
260	    private void logRedemptionAttempt(Order order, Long verifierId, String outcome, String reason) {
261	        User verifier = userRepository.findById(verifierId).orElse(null);
262	        if (verifier != null) {
263	            redemptionLogRepository.save(PickupRedemptionLog.builder()
264	                    .order(order).verifier(verifier).outcome(outcome).reason(reason).build());
265	        }
266	    }
267	
268	    private BigDecimal calculateDefaultFee(double distanceMiles) {
269	        return distanceMiles <= 5.0 ? SHORT_RANGE_FEE : LONG_RANGE_FEE;
270	    }
271	
272	    private String generateVerificationCode() {
273	        int code = 100000 + secureRandom.nextInt(900000);
274	        return String.valueOf(code);
275	    }
276	
277	    private OrderResponse toResponse(Order order) {
278	        return toResponse(order, true);
279	    }
280	
281	    private OrderResponse toResponse(Order order, boolean includeVerificationCode) {
282	        OrderResponse r = new OrderResponse();
283	        r.setId(order.getId());
284	        r.setCustomerId(order.getCustomer().getId());
285	        r.setSiteId(order.getSite().getId());
286	        r.setStatus(order.getStatus());
287	        r.setFulfillmentMode(order.getFulfillmentMode());
288	        r.setSubtotal(order.getSubtotal());
289	        r.setDeliveryFee(order.getDeliveryFee());
290	        r.setTotal(order.getTotal());
291	        r.setDeliveryZip(order.getDeliveryZip());
292	        r.setDeliveryDistanceMiles(order.getDeliveryDistanceMiles());
293	        r.setPickup(order.isPickup());
294	        r.setPickupVerificationCode(includeVerificationCode ? order.getPickupVerificationCode() : null);
295	        r.setPickupVerified(order.isPickupVerified());
296	        r.setCourierNotes(order.getCourierNotes());
297	        r.setVerifiedById(order.getVerifiedBy() != null ? order.getVerifiedBy().getId() : null);
298	        r.setVerifiedAt(order.getVerifiedAt());
299	        r.setCreatedAt(order.getCreatedAt());
300	        r.setUpdatedAt(order.getUpdatedAt());
301	        return r;
302	    }
