26	    public String generateToken(UserPrincipal principal) {
27	        Instant now = Instant.now();
28	        return Jwts.builder()
29	                .subject(principal.getId().toString())
30	                .claim("username", principal.getUsername())
31	                .claim("role", principal.getRole())
32	                .claim("siteId", principal.getSiteId())
33	                .claim("authTime", now.toEpochMilli())
34	                .claim("tokenVersion", principal.getTokenVersion())
35	                .issuedAt(Date.from(now))
36	                .expiration(Date.from(now.plusMillis(expirationMs)))
37	                .signWith(key)
38	                .compact();
39	    }
