25	@Slf4j
26	@Component
27	public class JwtAuthenticationFilter extends OncePerRequestFilter {
28	
29	    private final JwtTokenProvider tokenProvider;
30	    private final CustomUserDetailsService userDetailsService;
31	    private final UserRepository userRepository;
32	    private final AuditService auditService;
33	    private final long idleTimeoutMs;
34	
35	    public JwtAuthenticationFilter(JwtTokenProvider tokenProvider,
36	                                   CustomUserDetailsService userDetailsService,
37	                                   UserRepository userRepository,
38	                                   AuditService auditService,
39	                                   @Value("${app.security.idle-timeout-ms}") long idleTimeoutMs) {
40	        this.tokenProvider = tokenProvider;
41	        this.userDetailsService = userDetailsService;
42	        this.userRepository = userRepository;
43	        this.auditService = auditService;
44	        this.idleTimeoutMs = idleTimeoutMs;
45	    }
46	
47	    @Override
48	    protected void doFilterInternal(HttpServletRequest request,
49	                                    HttpServletResponse response,
50	                                    FilterChain filterChain) throws ServletException, IOException {
51	        String token = extractToken(request);
52	
53	        if (StringUtils.hasText(token)) {
54	            if (tokenProvider.validateToken(token)) {
55	                Long userId = tokenProvider.getUserIdFromToken(token);
56	                UserDetails userDetails = userDetailsService.loadUserById(userId);
57	
58	                if (!userDetails.isEnabled()) {
59	                    filterChain.doFilter(request, response);
60	                    return;
61	                }
62	
63	                // Check server-side idle timeout
64	                Optional<User> userOpt = userRepository.findById(userId);
65	                if (userOpt.isPresent()) {
66	                    User user = userOpt.get();
67	                    Instant lastActivity = user.getLastActivityAt();
68	                    if (lastActivity != null) {
69	                        long idleTime = Instant.now().toEpochMilli() - lastActivity.toEpochMilli();
70	                        if (idleTime > idleTimeoutMs) {
71	                            log.warn("Idle timeout exceeded for userId={}. Idle for {}ms, threshold={}ms",
72	                                    userId, idleTime, idleTimeoutMs);
73	                            SecurityContextHolder.clearContext();
74	                            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
75	                            response.getWriter().write("{\"error\":\"Session expired due to inactivity\"}");
76	                            response.setContentType("application/json");
77	                            return;
78	                        }
79	                    }
80	
81	                    // Check token version for revocation
82	                    long jwtTokenVersion = tokenProvider.getTokenVersionFromToken(token);
83	                    if (jwtTokenVersion != user.getTokenVersion()) {
84	                        log.warn("Token version mismatch for userId={}: jwt={}, db={}",
85	                                userId, jwtTokenVersion, user.getTokenVersion());
86	                        SecurityContextHolder.clearContext();
87	                        response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
88	                        response.setContentType("application/json");
89	                        response.getWriter().write("{\"error\":\"Token has been revoked\"}");
90	                        return;
91	                    }
92	
93	                    // Update lastActivityAt, but skip DB write if updated within last 60s to reduce load
94	                    Instant now = Instant.now();
95	                    if (lastActivity == null || now.toEpochMilli() - lastActivity.toEpochMilli() > 60_000) {
96	                        user.setLastActivityAt(now);
97	                        userRepository.save(user);
98	                        try {
99	                            auditService.logSystemAction("SESSION_ACTIVITY", "User", userId,
100	                                    "Session activity updated");
101	                        } catch (Exception ignored) {
102	                            // Non-critical — don't fail the request for audit logging
103	                        }
104	                    }
105	                }
106	
107	                UsernamePasswordAuthenticationToken authentication =
108	                        new UsernamePasswordAuthenticationToken(userDetails, null, userDetails.getAuthorities());
109	                authentication.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
110	
111	                SecurityContextHolder.getContext().setAuthentication(authentication);
112	
113	                // Sliding session: refresh token when past half its lifetime
114	                long authTime = tokenProvider.getAuthTimeFromToken(token);
115	                long halfLife = idleTimeoutMs / 2;
116	                if (Instant.now().toEpochMilli() - authTime > halfLife) {
117	                    String refreshedToken = tokenProvider.generateToken((UserPrincipal) userDetails);
118	                    response.setHeader("X-Refreshed-Token", refreshedToken);
119	                }
120	
121	                log.debug("JWT authentication successful for userId={}", userId);
122	            } else {
123	                log.warn("Invalid JWT token received from {}", request.getRemoteAddr());
124	            }
125	        }
126	
127	        filterChain.doFilter(request, response);
128	    }
129	
130	    private String extractToken(HttpServletRequest request) {
131	        String bearer = request.getHeader("Authorization");
132	        if (StringUtils.hasText(bearer) && bearer.startsWith("Bearer ")) {
133	            return bearer.substring(7);
134	        }
135	        return null;
136	    }
137	}
