3	import jakarta.servlet.FilterChain;
4	import jakarta.servlet.ServletException;
5	import jakarta.servlet.http.HttpServletRequest;
6	import jakarta.servlet.http.HttpServletResponse;
7	import org.springframework.http.HttpStatus;
8	import org.springframework.stereotype.Component;
9	import org.springframework.web.filter.OncePerRequestFilter;
10	
11	import java.io.IOException;
12	import java.util.Map;
13	import java.util.concurrent.ConcurrentHashMap;
14	import java.util.concurrent.atomic.AtomicInteger;
15	
16	/**
17	 * Simple in-memory rate limiter for authentication endpoints.
18	 * Limits to 10 requests per minute per IP for /api/auth/** paths.
19	 */
20	@Component
21	public class RateLimitFilter extends OncePerRequestFilter {
22	
23	    private static final int AUTH_MAX_REQUESTS = 10;
24	    private static final int GENERAL_MAX_REQUESTS = 60;
25	    private static final long WINDOW_MS = 60_000;
26	
27	    private static final java.util.Set<String> STRICT_PATHS = java.util.Set.of(
28	            "/api/auth/", "/api/community/posts/", "/api/analytics/events"
29	    );
30	
31	    private final Map<String, RateWindow> windows = new ConcurrentHashMap<>();
32	
33	    @Override
34	    protected void doFilterInternal(HttpServletRequest request,
35	                                    HttpServletResponse response,
36	                                    FilterChain filterChain) throws ServletException, IOException {
37	        String path = request.getRequestURI();
38	        boolean isStrictPath = STRICT_PATHS.stream().anyMatch(path::startsWith);
39	        if (!isStrictPath) {
40	            filterChain.doFilter(request, response);
41	            return;
42	        }
43	
44	        int maxRequests = path.startsWith("/api/auth/") ? AUTH_MAX_REQUESTS : GENERAL_MAX_REQUESTS;
45	
46	        String ip = getClientIp(request);
47	        RateWindow window = windows.compute(ip, (k, v) -> {
48	            long now = System.currentTimeMillis();
49	            if (v == null || now - v.startTime > WINDOW_MS) {
50	                return new RateWindow(now, new AtomicInteger(1));
51	            }
52	            v.count.incrementAndGet();
53	            return v;
54	        });
55	
56	        if (window.count.get() > maxRequests) {
57	            response.setStatus(HttpStatus.TOO_MANY_REQUESTS.value());
58	            response.setContentType("application/json");
59	            response.getWriter().write("{\"status\":429,\"error\":\"Too many requests. Try again later.\"}");
60	            return;
61	        }
62	
63	        filterChain.doFilter(request, response);
64	
65	        // Periodic cleanup of expired windows
66	        if (windows.size() > 1000) {
67	            long now = System.currentTimeMillis();
68	            windows.entrySet().removeIf(e -> now - e.getValue().startTime > WINDOW_MS);
69	        }
70	    }
71	
72	    /**
73	     * Returns client IP. Only trusts X-Forwarded-For when the direct connection
74	     * comes from a known reverse proxy (Docker internal or loopback).
75	     */
76	    private String getClientIp(HttpServletRequest request) {
77	        String remoteAddr = request.getRemoteAddr();
78	        // Only trust XFF from known reverse proxies (nginx in Docker, or loopback)
79	        if (remoteAddr != null && (remoteAddr.startsWith("172.") || remoteAddr.startsWith("10.")
80	                || remoteAddr.startsWith("192.168.") || "127.0.0.1".equals(remoteAddr) || "0:0:0:0:0:0:0:1".equals(remoteAddr))) {
81	            String xff = request.getHeader("X-Forwarded-For");
82	            if (xff != null && !xff.isEmpty()) {
83	                return xff.split(",")[0].trim();
84	            }
85	        }
86	        return remoteAddr;
87	    }
88	
89	    private static class RateWindow {
90	        final long startTime;
91	        final AtomicInteger count;
92	
93	        RateWindow(long startTime, AtomicInteger count) {
94	            this.startTime = startTime;
95	            this.count = count;
96	        }
97	    }
98	}
