26	/**
27	 * Intercepts @DataScope-annotated methods and injects multi-dimensional scope context:
28	 * site IDs, team ID, device hash, and work-order ID.
29	 *
30	 * When the annotation's requireDevice or requireWorkOrder flags are set, the aspect
31	 * enforces deny-by-default: the operation is rejected if the required dimension is
32	 * absent from the request context.
33	 */
34	@Slf4j
35	@Aspect
36	@Component
37	@RequiredArgsConstructor
38	public class DataScopeAspect {
39	
40	    private final OrganizationRepository organizationRepository;
41	    private final UserRepository userRepository;
42	
43	    @Around("@annotation(com.eaglepoint.storehub.annotation.DataScope)")
44	    public Object applyDataScope(ProceedingJoinPoint joinPoint) throws Throwable {
45	        // Read annotation attributes
46	        MethodSignature signature = (MethodSignature) joinPoint.getSignature();
47	        Method method = signature.getMethod();
48	        DataScope annotation = method.getAnnotation(DataScope.class);
49	        boolean requireDevice = annotation != null && annotation.requireDevice();
50	        boolean requireWorkOrder = annotation != null && annotation.requireWorkOrder();
51	
52	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
53	        if (auth != null && auth.getPrincipal() instanceof UserPrincipal principal) {
54	            Role role = Role.valueOf(principal.getRole());
55	
56	            // Site scope
57	            List<Long> visibleSiteIds;
58	            if (role == Role.ENTERPRISE_ADMIN) {
59	                visibleSiteIds = null;
60	            } else if (role == Role.SITE_MANAGER || role == Role.TEAM_LEAD) {
61	                visibleSiteIds = principal.getSiteId() != null
62	                        ? organizationRepository.findAllSiteIdsUnder(principal.getSiteId())
63	                        : List.of();
64	            } else {
65	                visibleSiteIds = principal.getSiteId() != null
66	                        ? List.of(principal.getSiteId())
67	                        : List.of();
68	            }
69	            DataScopeContext.set(visibleSiteIds);
70	
71	            // Team scope
72	            User user = userRepository.findById(principal.getId()).orElse(null);
73	            if (user != null && user.getTeam() != null) {
74	                DataScopeContext.setTeamId(user.getTeam().getId());
75	            }
76	
77	            // Device scope — derive from current request header
78	            ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
79	            if (attrs != null) {
80	                HttpServletRequest req = attrs.getRequest();
81	
82	                String deviceHeader = req.getHeader("X-Device-Fingerprint");
83	                if (deviceHeader != null && !deviceHeader.isBlank()) {
84	                    DataScopeContext.setDeviceHash(deviceHeader);
85	                }
86	
87	                // Work-order scope — from header or request parameter
88	                String workOrderHeader = req.getHeader("X-Work-Order-Id");
89	                if (workOrderHeader != null && !workOrderHeader.isBlank()) {
90	                    try {
91	                        DataScopeContext.setWorkOrderId(Long.parseLong(workOrderHeader.trim()));
92	                    } catch (NumberFormatException e) {
93	                        log.warn("Invalid X-Work-Order-Id header: {}", workOrderHeader);
94	                    }
95	                } else {
96	                    String workOrderParam = req.getParameter("workOrderId");
97	                    if (workOrderParam != null && !workOrderParam.isBlank()) {
98	                        try {
99	                            DataScopeContext.setWorkOrderId(Long.parseLong(workOrderParam.trim()));
100	                        } catch (NumberFormatException e) {
101	                            log.warn("Invalid workOrderId parameter: {}", workOrderParam);
102	                        }
103	                    }
104	                }
105	            }
106	
107	            // Enforce required dimensions (deny-by-default)
108	            if (requireDevice && DataScopeContext.getDeviceHash() == null) {
109	                DataScopeContext.clear();
110	                throw new AccessDeniedException(
111	                        "Device scope required but no device fingerprint provided (X-Device-Fingerprint header)");
112	            }
113	            if (requireWorkOrder && DataScopeContext.getWorkOrderId() == null) {
114	                DataScopeContext.clear();
115	                throw new AccessDeniedException(
116	                        "Work-order scope required but no work-order ID provided (X-Work-Order-Id header)");
117	            }
118	        }
119	
120	        try {
121	            return joinPoint.proceed();
122	        } finally {
123	            DataScopeContext.clear();
124	        }
125	    }
126	}
